_BOARD_ALIASES = {
    "cbse": "cbse",
    "karnataka kseeb": "karnataka kseeb",
    "maharashtra msbshse": "maharashtra msbshse",
    "icse": "icse",
}
_SUBJECT_ALIASES = {
    "history": {"history", "social science"},
    "geography": {"geography", "social science"},
    "civics": {"civics", "social science", "political science"},
    "economics": {"economics", "social science"},
    "physics": {"physics", "science"},
    "chemistry": {"chemistry", "science"},
    "biology": {"biology", "science"},
}

def _norm(value: object) -> str:
    return re.sub(r"[^a-z0-9]+", " ", str(value or "").lower()).strip()

def _grade_key(value: object) -> str:
    text = _norm(value)
    m = re.search(r"\d+", text)
    return str(int(m.group(0))) if m else text

def _subject_keys(subject: object) -> set[str]:
    key = _norm(subject)
    return {key} | _SUBJECT_ALIASES.get(key, set())

def _board_matches(want: str, got: str) -> bool:
    return want == got or want in got or got in want

def lookup_duration_minutes(*, board: str = "", grade: str = "", subject: str = "", chapter_title: str = "") -> int | None:
    want_board = _norm(board)
    want_grade = _grade_key(grade)
    want_subjects = _subject_keys(subject)
    want_chapter = _norm(chapter_title)
    if not (want_board and want_grade and want_chapter):
        return None
    for row_board, row_grade, row_subject, row_chapter, minutes in _DURATION_ROWS:
        if not _board_matches(want_board, _norm(row_board)):
            continue
        if want_grade != _grade_key(row_grade):
            continue
        if _norm(row_subject) not in want_subjects:
            continue
        if _norm(row_chapter) == want_chapter:
            return int(minutes)
    return None
